#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 105
#define MAX_M 105
// Define the structure for a branch
typedef struct Branch {
    int parent;
    int weight;
    int acorns;
    struct Branch* children;
} Branch;
// Function to create a new branch
Branch* createBranch(int parent, int weight) {
    Branch* branch = (Branch*) malloc(sizeof(Branch));
    branch->parent = parent;
    branch->weight = weight;
    branch->acorns = 0;
    branch->children = NULL;
    return branch;
}
// Function to add a child to a branch
void addChild(Branch* parent, Branch* child) {
    // Add child to the end of the children list
    if (parent->children == NULL) {
        parent->children = child;
    } else {
        Branch* current = parent->children;
        while (current->children != NULL) {
            current = current->children;
        }
        current->children = child;
    }
}
// Function to perform DFS on the tree
int dfs(Branch* branch, int* state) {
    // If the branch has fallen, return 0
    if (branch->weight < branch->acorns) {
        return branch->acorns;
    }
    // Recursively visit all children
    Branch* current = branch->children;
    while (current != NULL) {
        int fallen = dfs(current, state);
        if (fallen > 0) {
            // If a child has fallen, update the state and return
            *state = 1;
            return fallen;
        }
        current = current->children;
    }
    return 0;
}
// Function to handle an event
void handleEvent(Branch** branches, int n, int m, int state, int type, int u, int x) {
    // If the event is of type 1, add acorns to the branch
    if (type == 1) {
        branches[u]->acorns += x;
        // Perform DFS to find the branch that falls down
        int fallen = dfs(branches[u], &state);
        if (fallen > 0) {
            printf("%d\n", u);
        } else {
            printf("0\n");
        }
    } else if (type == 2) {
        // If the event is of type 2, count the number of acorns that fall down
        int count = 0;
        Branch* current = branches[u]->children;
        while (current != NULL) {
            count += current->acorns;
            current = current->children;
        }
        printf("%d\n", count);
    }
}
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n, m;
        scanf("%d %d", &n, &m);
        Branch** branches = (Branch**) malloc(n * sizeof(Branch*));
        for (int i = 0; i < n; i++) {
            int parent, weight;
            scanf("%d %d", &parent, &weight);
            branches[i] = createBranch(parent, weight);
        }
        for (int i = 0; i < n; i++) {
            if (branches[i]->parent > 0) {
                addChild(branches[branches[i]->parent - 1], branches[i]);
            }
        }
        for (int i = 0; i < m; i++) {
            int state, type, u, x;
            scanf("%d %d", &state, &type);
            if (type == 1) {
                scanf("%d %d", &u, &x);
                handleEvent(branches, n, m, state, type, u - 1, x);
            } else if (type == 2) {
                scanf("%d", &u);
                handleEvent(branches, n, m, state, type, u - 1, 0);
            }
        }
        free(branches);
    }
    return 0;
}

