import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    static class Branch {
        int parent;
        int weight;
        int acorns;
        ArrayList<Branch> children;
        public Branch(int parent, int weight) {
            this.parent = parent;
            this.weight = weight;
            this.acorns = 0;
            this.children = new ArrayList<>();
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            Branch[] branches = new Branch[n];
            for (int i = 0; i < n; i++) {
                int parent = scanner.nextInt();
                int weight = scanner.nextInt();
                branches[i] = new Branch(parent, weight);
            }
            for (int i = 0; i < n; i++) {
                if (branches[i].parent > 0) {
                    branches[branches[i].parent - 1].children.add(branches[i]);
                }
            }
            for (int i = 0; i < m; i++) {
                int state = scanner.nextInt();
                int type = scanner.nextInt();
                if (type == 1) {
                    int u = scanner.nextInt();
                    int x = scanner.nextInt();
                    handleEvent(branches, n, m, state, type, u - 1, x);
                } else if (type == 2) {
                    int u = scanner.nextInt();
                    handleEvent(branches, n, m, state, type, u - 1, 0);
                }
            }
        }
    }
    public static void handleEvent(Branch[] branches, int n, int m, int state, int type, int u, int x) {
        // If the event is of type 1, add acorns to the branch
        if (type == 1) {
            branches[u].acorns += x;
            // Perform DFS to find the branch that falls down
            int fallen = dfs(branches[u], state);
            if (fallen > 0) {
                System.out.println(u + 1);
            } else {
                System.out.println(0);
            }
        } else if (type == 2) {
            // If the event is of type 2, count the number of acorns that fall down
            int count = 0;
            for (Branch child : branches[u].children) {
                count += child.acorns;
            }
            System.out.println(count);
        }
    }
    public static int dfs(Branch branch, int state) {
        // If the branch has fallen, return 0
        if (branch.weight < branch.acorns) {
            return branch.acorns;
        }
        // Recursively visit all children
        for (Branch child : branch.children) {
            int fallen = dfs(child, state);
            if (fallen > 0) {
                // If a child has fallen, update the state and return
                state = 1;
                return fallen;
            }
        }
        return 0;
    }
